docinfo.macros:
% Standard number sets
\newcommand{\N}{\mathbb N}
\newcommand{\Z}{\mathbb Z}
\newcommand{\Q}{\mathbb Q}
\newcommand{\R}{\mathbb R}
\newcommand{\C}{\mathbb C}

% Quantum mechanics notation
\newcommand{\ket}[1]{\left|#1\right\rangle}
\newcommand{\bra}[1]{\left\langle #1\right|}
\newcommand{\braket}[2]{\left\langle #1|#2\right\rangle}
\newcommand{\ketbra}[2]{\left|#1\right\rangle\left\langle #2\right|}
\newcommand{\expect}[1]{\left\langle #1 \right\rangle}
\newcommand{\expval}[3]{\left\langle #1 | #2 | #3 \right\rangle}
\newcommand{\comm}[2]{\left[#1, #2\right]}
\newcommand{\anticomm}[2]{\left\{#1, #2\right\}}
\newcommand{\norm}[1]{\left\|#1\right\|}

% Common operators
\newcommand{\HH}{\hat{H}}
\newcommand{\pp}{\hat{\mathbf{p}}}
\newcommand{\rr}{\hat{\mathbf{r}}}
\newcommand{\AA}{\hat{A}}
\newcommand{\BB}{\hat{B}}
\newcommand{\LL}{\hat{\mathbf{L}}}
\newcommand{\SS}{\hat{\mathbf{S}}}
\newcommand{\II}{\hat{I}}
\newcommand{\PP}{\hat{P}}
\newcommand{\UU}{\hat{U}}

% Other symbols
\newcommand{\hbar}{\hbar}
\newcommand{\del}{\nabla}
\newcommand{\del2}{\nabla^2}
\newcommand{\Hilbert}{\mathcal{H}}
\newcommand{\Fock}{\mathcal{F}}

docinfo.latex-image-preamble:
\usepackage{tikz, pgfplots, amssymb, amsmath}
\usetikzlibrary{positioning, matrix, arrows, shapes, decorations, shadows, fadings, patterns}
\usetikzlibrary{decorations.markings}
\pgfplotsset{compat=1.18}
